INSERT INTO `MD_PROCESS` (`ID_DLK_PROCESS`, `ID_DLK_PARENT_COMPANY`, `ID_DLK_PRODUCTION_CHAIN`, `ORDEN_PRECEDENCIA_PROCESS`, `COD_PROCESS`, `NAME_PROCESS`, `DES_PROCESS`, `OBJETIVE_PROCESS`, `CRITICALITY_PROCESS`, `OUTSOURCED_PROCESS`, `ESTIMATED_TIME_PROCESS`, `RESPONSIBLE_UNIT`, `RESPONSIBLE_PROCESS`, `PROCESS_CERTIFICATION`, `STATE_PROCESS`, `COD_USUARIO_CARGA_DL`, `FEH_PROCESO_CARGA_DL`, `FEH_PROCESO_MODIF_DL`, `DES_ACCION`, `FLG_STATUT_ACTIF`) VALUES
(001, 001, 02, 2, 'UDP', 'Unidad Desarrollo del Producto', 'Desarrollo técnico integral del producto (prenda textil)', 'Desarrollar prototipos técnicos, elaborar fichas técnicas, crear moldes escalados y coordinar con todas las áreas para garantizar la factibilidad de producción de una Orden de Pedido', 'Opciones: 2=Alta, 1=Media y 0=Baja\r\nAlta: Para desarrollo de productos nuevos\r\nMedia: Para productos que ya cuentan con diseño\r\nBaja: Para muestras', 'Opciones: 2=Si, 1=No y 0=Muestra Interna\r\n(2) Maquila: Cuando el volumen de producción sobrepasa la capacidad instalada de la fábrica.\r\n(1) InHouse: Cuando se produce en la fábrica.\r\n(0) InHouse: Para muestras.', 45, 'UDP - Unidad de Desarrollo de Producto', 'Nancy Marzal (Coordinación) / Dana Zavalaga (Analista) /Otros', 'No', 1, 'MAGREDA', '2026-03-02 19:13:20', '2026-03-02 20:18:39', 'INSERT', 1),
(002, 001, 02, 3, 'PG', 'Coordinación integral producción', 'Coordinar y Ejecutar la atención de una Orden de Pedido de marcas propias y de marcas externas internacionales. Responsable del Flujo del Proceso: Corte → Bordado → Confección → Acabados', 'Coordinar y ejecutar la producción desde recepción de Orden de Pedido  (OP) hasta producto terminado, garantizando calidad, tiempos y proceso completo.', 'Opciones: 2=Alta, 1=Media y 0=Baja\r\nAlta: Responsable del más del 50% de la atención de la Orden de Pedidos de exportación.\r\nMedia: Para Marcas propias.\r\nBaja: Para muestras', 'Opciones: 2=Si, 1=No y 0=Muestra\r\nMaquila: OP sobrepaso capacidad instalada de fábrica.\r\nInHouse: OP puede ser atendida por Fabrica\r\nInHouse: Muestra', 120, 'Producción General', 'Ing. Guillermo Pachas/ Ricardo Higa', 'Intertek', 1, 'MAGREDA', '2026-03-02 19:41:22', '2026-03-02 20:18:22', 'INSERT', 1),
(003, 001, 02, 1, 'COM', 'Gestión comercial y generación de órdenes de pedido', 'Contacta con cliente, recibe la OP, la pasa a formato KUSA y envía a áreas responsables para su atención.', 'Realizar estudio de mercado, generar diseños, coordinar con UDP para desarrollo técnico y gestionar el \r\nciclo completo de ventas B2C para marcas propias, para marcas externas atención completa de la OP.', 'Opciones: 1=Alta, 2=Media y 3=Baja\r\nAlta: Para marcas externas\r\nMedia: Para marcas propias\r\nBaja: Para muestras', 'Opciones: 1:Si, 2:No y 3:Muestras\r\n(1) Maquila: OP supera capacidad instalada de fábrica.\r\n(2) Inhouse: OP puede ser atendida por la fábrica.\r\n(3) Inhouse: muestra.\r\n', 54, 'Comercial', 'Blanca Olortegui', 'Datos requeridos: Nombre, Entidad Certificadora, fecha de expedición y fecha de caducidad. Para todos los certificados.', 1, 'MAGREDA', '2026-03-02 20:28:47', '2026-03-02 20:28:47', 'INSERT', 1);
